window.__QUIZ_DATA__=[{"id":"objective>Physics>2023>1","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : HUMIDITY AND THE WEATHER","question":"The instrument used to measure relative humidity is a","images":[],"options":{"A":"barometer.","B":"hydrometer.","C":"hygrometer.","D":"manometer."},"answer":"C","explanation":"The instrument used to measure relative humidity is a hygrometer. Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. A hygrometer is a device used for measuring the moisture content in the atmosphere, soil, or confined spaces.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>2","subject":"Physics","year":"2023","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Which part of the human eye performs the same function as the diaphragm in a lens camera?","images":[],"options":{"A":"Choroid","B":"Iris","C":"Cornea","D":"Retina"},"answer":"B","explanation":"The part of the human eye that performs a function similar to the diaphragm in a camera lens is the Iris.    Just like the diaphragm in a camera lens controls the amount of light entering the camera, the iris in the eye controls the amount of light that enters the eye by adjusting the size of the pupil. It can contract or expand to regulate the size of the pupil in response to varying light conditions, thus controlling the amount of light that reaches the retina at the back of the eye.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>3","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An electron moves from an energy level of -8.6 eV to another level of -3.5 eV. Determine the frequency of the absorbed radiation. [1 eV = 1.6 \u00d7 10-19 J, h = 6.6 \u00d7 10-34 Js]","images":[],"options":{"A":"1.24 \u00d7 1015 Hz","B":"2.93 \u00d7 1015 Hz","C":"3.59 \u00d7 1016 Hz","D":"5.39 \u00d7 1016 Hz"},"answer":"A","explanation":"h=6.6\u00d710-34Js,1eV=1.6\u00d710-19J,E1=-8.6eV,E2=-3.5eV,f=?  \u2206E=hf  f=\u2206Eh  \u2206E=E2-E1=-3.5eV-(-8.6eV)=-3.5eV+8.6eV  \u2206E=5.1eV=5.1\u00d71.6\u00d710-19=8.16\u00d710-19J  So,  f=8.16 \u00d7 10-196.6 \u00d7 10-34  \u2234f=1.24\u00d71015Hz","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>4","subject":"Physics","year":"2023","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"A ball of mass 0.8 kg is dropped from a height, H. Just before hitting the ground, its velocity is 5.0 ms-1. Determine H.  [g = 10 ms-2]","images":[],"options":{"A":"1.25 m","B":"1.60 m","C":"4.00 m","D":"6.25 m"},"answer":"A","explanation":"u = 0, g = 10 ms-2, v = 5 ms-1, h = ?  From v2 = u2 + 2gh  \u21d2  52 = 02 + 2 \u00d7 10 \u00d7 h  25 = 0 + 20h  25 = 20h  \u2234h=2520=1.25m","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>5","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : LATENT HEAT","question":"Which of the following statements about latent heat are correct?  I. When ice melts, latent heat is absorbed  II. When water freezes, latent heat is given off   III. When water evaporates, latent heat is absorbed  IV. When water vapour condenses, latent heat is absorbed","images":[],"options":{"A":"I and IV only","B":"II and III only","C":"I, II and III only","D":"II, III and IV only."},"answer":"C","explanation":"Latent heat is the heat absorbed or released by a substance during a phase change. This is typically when the heat changes the state of a substance but not its temperature. So, when ice melts (solid to liquid), latent heat is absorbed. When water freezes (liquid to solid), latent heat is given off. When water evaporates (liquid to gas), latent heat is absorbed. However, when water vapour condenses (gas to liquid), latent heat is given off, not absorbed. Therefore, the correct statements are I, II and III only.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>6","subject":"Physics","year":"2023","type":"Objective","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"Increasing the frequency of a sound wave produces a sound with","images":[],"options":{"A":"longer wavelength.","B":"reduced loudness.","C":"higher pitch.","D":"more overtones."},"answer":"C","explanation":"The pitch of a sound is determined by its frequency. Higher frequencies correspond to higher pitches. For example, a high-pitched sound like a whistle has a higher frequency than a low-pitched sound like a drum.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>7","subject":"Physics","year":"2023","type":"Objective","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"Which of the following diagrams correctly illustrates the mode of oscillation of air in a tube for the first overtone?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"The diagram above, is a full wavelength and the length of an open pipe during first overtone equals one wavelength i.e.  l  = \u03bb","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>8","subject":"Physics","year":"2023","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"In a mass spectrometer, an ion of charge, q, and mass, m, moving in a path of radius, r, in a field of flux density, B, has a speed of","images":[],"options":{"A":"mrqB.","B":"mqqr.","C":"Bqrm.","D":"mqBr."},"answer":"C","explanation":"F=qvB(forceonamovingchargeinamagneticfield)andF=mv2r(centripetalforce)  equatingF,  qvB=mv2r  qB=mvr  qBr=mv  \u2234v=Bqrm","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>9","subject":"Physics","year":"2023","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"A sound of frequency 512 Hz reaches a listener 100 m away. If the sound travels in air at s.t.p., what is its wavelength?  [speed of sound in air = 331 ms-1]","images":[],"options":{"A":"0.195 m","B":"0.646 m","C":"1.550 m","D":"5.120 m"},"answer":"B","explanation":"f=512Hz,v=331ms-1,\u03bb=?  v=f\u03bb  \u03bb=vf=331512  \u03bb=0.646m","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>10","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"In the Rutherford scattering experiment, a beam of alpha particles was fired at a thin gold film and few of the particles were deflected considerably. This shows that the nucleus of an atom","images":[],"options":{"A":"contains protons and electrons distributed in a tiny volume.","B":"is positively charged and is concentrated in a tiny volume.","C":"is distributed in a tiny volume and emits alpha particles.","D":"is concentrated in a tiny volume and contains alpha particles."},"answer":"B","explanation":"The Rutherford scattering experiment showed that the nucleus of an atom:    is concentrated in a tiny volume and is positively charged.    In the experiment, when alpha particles were fired at a thin gold foil, most of the alpha particles passed straight through, but a few were deflected considerably. This result led Rutherford to conclude that the positive charge of the atom is concentrated in a small, dense nucleus at the center of the atom. The fact that some alpha particles were deflected strongly indicated that there was a positively charged nucleus within the atom. This experiment was crucial in developing our understanding of atomic structure and led to the model of the atom with a central nucleus containing protons and neutrons, surrounded by electrons.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>11","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"A charge of 10 C is transferred across a potential difference of 220 V. Determine the work done.","images":[],"options":{"A":"22 J","B":"210 J","C":"230 J","D":"2200 J"},"answer":"D","explanation":"The work done in moving a charge across a potential difference is given by the formula W = QV, where W is the work done, Q is the charge and V is the potential difference. Substituting the given values, we get W = 10 C * 220 V = 2200 J. Hence, the work done is 2200 J.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>12","subject":"Physics","year":"2023","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"A solenoid is constructed by winding an insulated copper on a long test tube. A constant direct current is passed through the solenoid. Which of the following actions will not increase the strength of the magnetic field of the solenoid? Inserting a","images":[],"options":{"A":"nickel rod in the test tube.","B":"brass rod in the test tube.","C":"soft iron rod in the test tube.","D":"steel rod in the test tube."},"answer":"B","explanation":"Inserting a brass rod in the test tube will not increase the strength of the magnetic field of the solenoid.    The strength of the magnetic field inside a solenoid depends on factors such as the number of turns of wire, the current passing through it, and the core material within the solenoid. Materials with high permeability, like soft iron and steel, can enhance the strength of the magnetic field when inserted into the solenoid. Nickel, which also has some ferromagnetic properties, would have a similar effect.    However, brass is not a ferromagnetic material; it does not enhance the magnetic field strength when inserted into the solenoid. In fact, it might even slightly reduce the magnetic field strength due to its non-magnetic properties.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>13","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The following statements are advantages of a solid dielectric material between the plates of a capacitor except that","images":[],"options":{"A":"it keeps the plates at a fixed separation.","B":"the maximum potential difference the capacitor can withstand is increased.","C":"the capacitance of the capacitor of given dimensions is much greater than that of the plates in a vacuum.","D":"it increases the electrical conduction of the capacitor."},"answer":"D","explanation":"The statement that is not an advantage of a solid dielectric material between the plates of a capacitor is:    it increases the electrical conduction of the capacitor.    In fact, one of the primary advantages of using a solid dielectric material between the plates of a capacitor is that it reduces electrical conduction between the plates. Dielectric materials are insulators, and they prevent the flow of electric current between the plates, thus increasing the capacitor's ability to store charge.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>14","subject":"Physics","year":"2023","type":"Objective","topic":"MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS","question":"Which of the following statements about a ferromagnetic material is correct? It","images":[],"options":{"A":"attracts non-magnetic materials.","B":"has low relative permeability.","C":"repels other magnetic materials.","D":"has a high susceptibility."},"answer":"D","explanation":"The correct statement about a ferromagnetic material is:    It has a high susceptibility.    Ferromagnetic materials are characterized by having a high susceptibility, which means they are strongly attracted to magnetic fields. When placed in a magnetic field, ferromagnetic materials become magnetized and can themselves exhibit strong magnetic properties, attracting other magnetic materials. Ferromagnetic materials, such as iron, nickel, and cobalt, are commonly used in the construction of permanent magnets and electromagnets due to their strong response to magnetic fields.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>15","subject":"Physics","year":"2023","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A ball, P, is released from the roof of a building at the same time as another ball, Q, is thrown vertically upward from the base of the building. Which of the following statements is correct?","images":[],"options":{"A":"The acceleration of P is greater than that of Q and both are in the same direction.","B":"The acceleration of P is equal to that of Q and both are in the same direction.","C":"The acceleration of P is equal to that of Q and are in opposite directions.","D":"The acceleration of P is less than that of Q and both are in the same direction."},"answer":"B","explanation":"The correct statement is:    The acceleration of P is equal to that of Q and both are in the same direction.    When ball P is released from the roof of the building, it falls freely under the influence of gravity. Similarly, when ball Q is thrown vertically upward, it initially moves upward but is also under the influence of gravity, which acts to slow it down and eventually make it fall back down.    Both balls, P and Q, are subjected to the same acceleration due to gravity (assuming no other forces are acting on them), which is approximately 9.8 m/s\u00b2 near the surface of the Earth, and this acceleration acts in the downward direction. Therefore, the acceleration of P is equal to the acceleration of Q, and both are in the same direction, which is downward.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>16","subject":"Physics","year":"2023","type":"Objective","topic":"GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY","question":"A planet has mass, M, and radius R, If the universal gravitational constant is G, what is the expression for the escape velocity of an object on the planet?","images":[],"options":{"A":"(2GR)1/2","B":"(GR2)1/2","C":"(GMR)1/2","D":"(2GMR)1/2"},"answer":"D","explanation":"The expression for the escape velocity (ve) of an object from a planet of mass M and radius R using the universal gravitational constant G is:    ve=&radic;2GMR&nbsp;  So,thecorrectoptionis:  (2GMR)1/2","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>17","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"The specific latent heat of vapourization of lead is 8.7 \u00d7 105 Jkg-1. This means that 8.7 \u00d7 105 J of thermal energy is required to change","images":[],"options":{"A":"1 kg of molten lead to vapour at constant temperature and pressure.","B":"1 kg of solid lead to vapour at constant temperature and pressure.","C":"a given mass of molten lead to vapour at constant temperature and pressure.","D":"1 kg of molten lead to vapour for every degree rise in temperature."},"answer":"A","explanation":"The specific latent heat of vaporization of lead is the amount of thermal energy required to change 1 kg of molten lead to vapor at constant temperature and pressure.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>18","subject":"Physics","year":"2023","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"A 100 kg device is pulled up a plane inclined at 30\u00b0 to the horizontal with a force of 1000 N. If the coefficient of friction between the device and the surface is 0.25, determine the total force opposing the motion.  [ g = 10 ms-2]","images":[],"options":{"A":"216.5 N","B":"283.5 N","C":"716.5 N","D":"975.0 N"},"answer":"C","explanation":"The forces opposing the motion of the device are \"mgsin \u03b8\" and \"\u03bcN\" where N is the normal reaction  From the diagram, on resolving to components, N = mgcos \u03b8  Total opposing force = mgsin \u03b8 + \u03bcmgcos \u03b8 = mg(sin \u03b8 + \u03bccos \u03b8)  = 100 \u00d7 10 \u00d7 (sin 30o + 0.25 \u00d7 cos 30o)  = 1000 \u00d7 (0.5 + 0.2165)  = 1000 \u00d7 0.7165  = 716.5 N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2023>19","subject":"Physics","year":"2023","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"Two objects, A and B, accelerate from rest at uniform rates. B accelerates twice as much as Compared to A, B travels","images":[],"options":{"A":"two times as far.","B":"three times as far.","C":"six times as far.","D":"at the same distance as A."},"answer":"A","explanation":"aB=2aA(Given)  Froms=ut+12at2,  sA=12aAt2andsB=12aBt2(sinceu=0)  sB=12\u00d7(2aA)\u00d7t2(from aB = 2aA)  sB=aAt2---(i)  SincesA=12aAt2  2sA=aAt2---(ii)  equatingequation(i)and(ii)  sB=2sA  ThereforeBtravelstwotimesasfar.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>20","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"The diagram above illustrates a hot metal suspended at the centre of a closed uniform box. Thermometers E, F, G and H are placed in contact with four sides of the box. Which of the thermometers would register the highest temperature?","images":["data:image/png;base64,"],"options":{"A":"E","B":"F","C":"G","D":"H"},"answer":"A","explanation":"Thermometer E would register the highest temperature since the hot metal is suspended from its side.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>21","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : EVAPORATION AND BOILING","question":"A liquid is left in an open dish. After several days, there is less liquid in the dish. Which of the following statements explains this observation? The","images":[],"options":{"A":"most energetic molecules leave the surface and return.","B":"most energetic molecules leave the surface and escape into the air.","C":"least energetic molecules leave the surface and return.","D":"least energetic molecules leave the surface and escape into air."},"answer":"B","explanation":"The statement that explains the observation is:    The most energetic molecules leave the surface and escape into the air.    This phenomenon is known as evaporation. In a liquid, molecules have varying energies, and the molecules with higher kinetic energies (the most energetic ones) are more likely to overcome the attractive forces within the liquid and transition into the gaseous phase. These molecules escape from the surface of the liquid into the air, gradually reducing the amount of liquid in the open dish. Evaporation is a process that occurs continuously as long as there is a liquid exposed to the air.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>22","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"The colours of the visible light region of the electromagnetic spectrum that have the shortest and longest wavelengths respectively are","images":[],"options":{"A":"red and blue.","B":"yellow and blue.","C":"indigo and violet.","D":"violet and red."},"answer":"D","explanation":"The colors of the visible light spectrum with the shortest and longest wavelengths respectively are:    Violet and red.    Violet light has the shortest wavelength among visible colors, while red light has the longest wavelength. The visible light spectrum, in order of increasing wavelength, goes from violet to blue, green, yellow, orange, and finally red.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>23","subject":"Physics","year":"2023","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"Which of the following equations is not a correct mirror formula? [The symbols have their usual meanings]","images":[],"options":{"A":"1f=1u+1v","B":"N=360\u03b8-1","C":"f=1D","D":"m=vu"},"answer":"C","explanation":"Theequationf=1Disnotacorrectmirrorformula.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>24","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An atom in an excited state is one whose","images":[],"options":{"A":"potential energy is minimum.","B":"potential energy is maximum.","C":"electrons are in the conduction band.","D":"electrons have moved to a higher energy level."},"answer":"D","explanation":"An atom in an excited state is one whose electrons have moved to a higher energy level.    In an atom, electrons are typically found in specific energy levels or orbitals. When an electron absorbs energy, it can move from a lower energy level to a higher energy level, which is referred to as an excited state. In this higher energy state, the electron is farther from the nucleus and has more potential energy. When the electron returns to its lower energy level, it emits the excess energy as electromagnetic radiation, often in the form of visible light. This is what gives rise to the characteristic spectral lines observed in spectroscopy.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>25","subject":"Physics","year":"2023","type":"Objective","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"The conclusive test for magnetism in a steel bar suspended horizontally at its midpoint is when the bar","images":[],"options":{"A":"always settles in the magnetic N-S direction.","B":"always settles in the magnetic E-W direction.","C":"is repelled by a magnet.","D":"is attracted by a magnet."},"answer":"A","explanation":"The conclusive test for magnetism in a steel bar suspended horizontally at its midpoint is when the bar always settles in the magnetic N-S (North-South) direction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>26","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"Which of the following devices is used to compare the relative magnitudes of charges on two given bodies?","images":[],"options":{"A":"Electrophorus","B":"Ebonite rod","C":"Proof plane","D":"Gold leaf electroscope"},"answer":"D","explanation":"The device used to compare the relative magnitudes of charges on two given bodies is a gold leaf electroscope.    A gold leaf electroscope consists of two thin gold leaves that are attached to a metal rod inside a glass or plastic enclosure. When a charged object is brought near the metal rod, it induces a charge on the leaves. The leaves, being like charges, repel each other and spread apart. By observing the degree to which the leaves separate, you can compare the relative magnitudes of charges on different bodies. This makes a gold leaf electroscope a valuable tool for demonstrating the presence and relative strength of electric charges.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>27","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"A direct current cannot pass through a parallel plate capacitor because","images":[],"options":{"A":"the plates are non-conducting.","B":"the plates have equal but opposite charges.","C":"there is a leakage of charge from the plates.","D":"the dielectric between the plates is non-conducting."},"answer":"D","explanation":"A direct current (DC) cannot pass through a parallel plate capacitor because the dielectric between the plates is non-conducting.    In a parallel plate capacitor, two conductive plates are separated by a dielectric material (usually an insulator). When a voltage (potential difference) is applied across the plates, it creates an electric field between them, which stores electrical energy in the form of electric potential. The dielectric material between the plates is a non-conducting material, which means it does not allow the flow of electric current. Therefore, in a DC circuit, where current is the flow of charge over time, current cannot flow through the dielectric. Instead, the dielectric serves to store energy in the electric field between the plates without allowing the passage of charge.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>28","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"The process of producing electric current by a changing magnetic field is referred to as","images":[],"options":{"A":"flux linkage.","B":"magnet induction.","C":"electromagnetic induction.","D":"electrostatic induction."},"answer":"C","explanation":"The process of producing electric current by a changing magnetic field is referred to as electromagnetic induction.    Electromagnetic induction is a phenomenon in which a voltage is generated in a conductor when it is exposed to a changing magnetic field. This voltage can then be used to drive an electric current.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>29","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The sagging of overhead electrical wires is caused by","images":[],"options":{"A":"rough handling.","B":"radiation of heat.","C":"linear expansion.","D":"gravitational attraction."},"answer":"C","explanation":"The sagging of overhead electrical wires is caused by linear expansion.    Linear expansion is the tendency of materials to expand in length when they are heated. When overhead electrical wires are heated by the sun, they expand and sag.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>30","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"A cell of emf 2 V has an internal resistance of 0.5 \u03a9. A current of 0.4 A passes through an external resistor, P. Determine the resistance of P.","images":[],"options":{"A":"5 \u03a9","B":"4.5 \u03a9","C":"4 \u03a9","D":"1 \u03a9"},"answer":"B","explanation":"E=2V,r=0.5\u03a9,I=0.4A,P=?  E=I(R+r)  2=0.4(R+0.5)  20.4=R+0.5  5=R+0.5  R=5-0.5=4.5\u03a9  \u2234Theexternalresistor,Pis4.5\u03a9.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>31","subject":"Physics","year":"2023","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The property of a body that determines the direction of heat flow when the body is in contact with another body is the","images":[],"options":{"A":"power.","B":"heat capacity.","C":"temperature.","D":"mass."},"answer":"C","explanation":"The property of a body that determines the direction of heat flow when the body is in contact with another body is the temperature.    Heat naturally flows from a body at a higher temperature to a body at a lower temperature. Temperature is a measure of the average kinetic energy of the particles in a substance. When two objects at different temperatures come into contact, heat energy tends to transfer from the warmer object to the cooler one until they reach thermal equilibrium (they are at the same temperature). This is known as the second law of thermodynamics, which describes the direction of heat flow.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>32","subject":"Physics","year":"2023","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : RESONANCE","question":"In an RLC series circuit at resonance, the voltages across the resistor and the inductor are 30 V and 40 V respectively. Determine the voltage across the capacitor.","images":[],"options":{"A":"30 V","B":"40 V","C":"50 V","D":"70 V"},"answer":"B","explanation":"At resonance, the inductive reactance is equal to the capacitive reactance. This means that the voltage across the inductor is also equal to the voltage across the capacitor.    Therefore, the voltage across the capacitor is 40 V.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>33","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT","question":"The purpose of commutators in a direct current motor is to","images":[],"options":{"A":"increase the efficiency of the motor.","B":"reverse the direction of the current after every half rotation.","C":"enable a uniform couple to act on the coil.","D":"increase the number of rotations per second."},"answer":"B","explanation":"The purpose of commutators in a direct current (DC) motor is to reverse the direction of the current after every half rotation.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>34","subject":"Physics","year":"2023","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A lead bullet of mass 0.05 kg is fired with a speed of 200 ms-1 into a lead block of mass 0.95 kg at rest. Given that the lead block moves after the impact, determine its kinetic energy.","images":[],"options":{"A":"50 J","B":"100 J","C":"150 J","D":"200 J"},"answer":"A","explanation":"mbullet=0.05kg,vbullet=200ms-1,mblock=0.95kg,ublock=0  Foraninelasticcollision:  mbullet\u00d7vbullet+mblock\u00d7vblock=(mbullet+mblock)v  0.05\u00d7200+0.95\u00d70=(0.05+0.95)v  10+0=v  v=10ms-1  Kineticenergyoftheblock=12mv2  K.E=12\u00d7(0.05+0.95)\u00d7102(thebulletnowpartoftheblock)  =12\u00d71\u00d7102  =12x1x100  =50J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>35","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"What is the name given to the force of attraction between the nucleons in the nucleus of an atom?","images":[],"options":{"A":"Gravitational force","B":"Nuclear force","C":"Electrostatic force","D":"Magnetic force"},"answer":"B","explanation":"The force of attraction between the nucleons (protons and neutrons) in the nucleus of an atom is called the nuclear force or strong nuclear force. This force is responsible for holding the protons and neutrons together in the nucleus despite the electrostatic repulsion between positively charged protons. It is one of the fundamental forces in nature and plays a crucial role in the stability of atomic nuclei.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>36","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"In a controlled thermal fission reactor, the use of control rods will not affect the","images":[],"options":{"A":"speed of the neutrons released on fission.","B":"rate of production of the neutrons.","C":"energy generated in the nuclear reactor.","D":"amount of radiations produced in the nuclear reactor."},"answer":"A","explanation":"In a controlled thermal fission reactor, control rods are used to absorb excess neutrons and thus control the rate of the nuclear reaction. They do not affect the speed of the neutrons released on fission. The speed of the neutrons is determined by the nature of the fission process itself, not by the control rods.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>37","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The most appropriate value of fuse for a kettle rated 220 V, 1.06 kW is","images":[],"options":{"A":"3 A.","B":"4 A.","C":"5 A.","D":"6 A."},"answer":"C","explanation":"V=220V,P=1.06kW=1060W,I=?  P=IV  I=PV=1060220  I\u22485A","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>38","subject":"Physics","year":"2023","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The type of mirror used by dentists to inspect the teeth of patients is a","images":[],"options":{"A":"convex mirror.","B":"concave mirror.","C":"plane mirror.","D":"cylindrical mirror."},"answer":"B","explanation":"The type of mirror used by dentists to inspect the teeth of patients is a concave mirror.    Concave mirrors are curved inwards and produce a magnified image of the object placed within its focus and pole. This is why dentists use concave mirrors to examine teeth, as it allows them to see the teeth in more detail.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>39","subject":"Physics","year":"2023","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"The diagram below illustrates a mode of vibration of a wire of length 125 cm. The speed of the waves along the wire is 120 ms-1. Use the diagram to answer questions 39 and 40.        Determine the wavelength of the waves.","images":["data:image/png;base64,"],"options":{"A":"0.25 m","B":"0.50 m","C":"0.75 m","D":"1.00 m"},"answer":"B","explanation":"Numberofcycles,n=212=52  Length=n\u03bb  \u03bb=Lengthn=1255/2  \u2234\u03bb=50cm=0.50m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>40","subject":"Physics","year":"2023","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"The diagram below illustrates a mode of vibration of a wire of length 125 cm. The speed of the waves along the wire is 120 ms-1. Use the diagram to answer questions 39 and 40.      Determine the frequency of the waves","images":["data:image/png;base64,"],"options":{"A":"24 Hz","B":"192 Hz","C":"240 Hz","D":"286 Hz"},"answer":"C","explanation":"v=120ms-1,\u03bb=0.50m,f=?  v=f\u03bb  f=v\u03bb=1200.5  \u2234f=240Hz","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>41","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"Which of the following statements about the properties of the electric field produced by charged parallel plates is not correct?","images":[],"options":{"A":"The electric field in the region outside the parallel plate is zero, except for the edge effects.","B":"The electric field is uniform everywhere in the space between the parallel plates.","C":"The magnitude of the electric field strength at any point between the plates, except near the edges, depends on the magnitude of the charge on each plate.","D":"The magnitude of the electric field strength at any point between the plates is directly proportional to the magnitude of the charge on each plate."},"answer":"D","explanation":"The magnitude of the electric field strength at any point between the plates is not directly proportional to the magnitude of the charge on each plate. Instead, it is directly proportional to the charge density (charge per unit area) on the plates. Therefore, if the charge on the plates is increased while keeping the area of the plates constant, the electric field strength will increase. However, if the area of the plates is also increased such that the charge density remains constant, the electric field strength will not change.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>42","subject":"Physics","year":"2023","type":"Objective","topic":"MOTION : RELATIVE MOTION","question":"A car, P, with a velocity of 30 ms-1 is travelling in the same direction as a car, Q, with a velocity of 20 ms-1. The velocity of P relative to Q is","images":[],"options":{"A":"50 ms-1.","B":"45 ms-1.","C":"20 ms-1.","D":"10 ms-1."},"answer":"D","explanation":"vP = 30 ms-1, vQ = 20 ms-1    vP = vQ + vP/Q    vP/Q = vP - vQ = 30 - 20    \u2234 vP/Q = 10 ms-1","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>43","subject":"Physics","year":"2023","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"The range of wavelengths of the infrared waves in an electromagnetic spectrum is 10-3 m to 10-6 m. The wavelength of the radiation is","images":[],"options":{"A":"equal to 103 m","B":"longer than 103 m","C":"shorter than 10-6 m","D":"longer than 10-6 m"},"answer":"D","explanation":"The range of wavelengths for infrared waves is given as 10-3 m to 10-6 m. This means that the wavelength of the radiation is longer than 10-6 m but shorter than 10-3 m. Therefore, the only correct option is that the wavelength is longer than 10-6 m.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>44","subject":"Physics","year":"2023","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"When an electron jumps directly from an orbit of n = 4 to n = 2,","images":[],"options":{"A":"a photon is emitted.","B":"a photon is absorbed.","C":"two photons are emitted.","D":"two photons are absorbed."},"answer":"A","explanation":"When an electron jumps directly from an orbit of n = 4 to n = 2, a photon is emitted.    This is a typical scenario in atomic physics where an electron transitions from a higher energy level (orbit) to a lower energy level. During this transition, the electron loses energy, and this energy is emitted in the form of a photon. The energy of the emitted photon corresponds to the energy difference between the two energy levels, as described by the quantization of energy levels in the Bohr model of the atom.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>45","subject":"Physics","year":"2023","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"When a light-weight body and a massive body are acted upon by the same force for the same period of time, the","images":[],"options":{"A":"momenta of both bodies remain the same.","B":"lighter body has a higher momentum.","C":"massive body has a higher momentum.","D":"massive body builds up a higher velocity."},"answer":"A","explanation":"When a light-weight body and a massive body are acted upon by the same force for the same period of time, the momenta of both bodies remain the same.    Given that the momenta of both the heavy and light bodies are same, it follows that the light body possesses a higher velocity compared to the heavy body.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>46","subject":"Physics","year":"2023","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"Which of the following devices is associated with alternating currents only?","images":[],"options":{"A":"Induction coil","B":"Lead-acid accumulator","C":"Step-up transformer","D":"Moving-coil galvanometer"},"answer":"C","explanation":"The device associated with alternating currents (AC) only from the provided options is the step-up transformer. Step-up transformers are specifically designed to work with alternating currents and are used to increase voltage levels in AC systems.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>47","subject":"Physics","year":"2023","type":"Objective","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"A body starts with an initial velocity of 20 ms-1 and moves with a uniform acceleration, a, for 15 seconds. Which of the following equations represents the distance, S, travelled?","images":[],"options":{"A":"S = 300 + 225/2a","B":"S = 300 + 2a/225","C":"S = 300 + 225a/2","D":"S = 300a + 225/2"},"answer":"C","explanation":"u = 20 ms-1, t = 15 s    S = ut + 1/2 at2    S = 20(15) + 1/2 \u00d7 a \u00d7 152    \u2234 S = 300 + 225a/2","marks":"1","difficulty":"1"},{"id":"objective>Physics>2023>48","subject":"Physics","year":"2023","type":"Objective","topic":"PROJECTILE MOTION :","question":"The ratio of maximum range to maximum height of a projectile is 4. Determine the angle of projection.","images":[],"options":{"A":"0\u00b0","B":"30\u00b0","C":"45\u00b0","D":"60\u00b0"},"answer":"C","explanation":"Maximumrange,R=u2sin2\u03b8g  Maximumheight,H=u2sin2\u03b82g  SinceR:H=4  \u21d2u2sin2\u03b8g:u2sin2\u03b82g=4  \u21d2u2sin2\u03b8g\u00f7u2sin2\u03b82g=4  \u21d2u2sin2\u03b8g\u00d72gu2sin2\u03b8=4  \u21d22sin2\u03b8sin2\u03b8=4  Sincesin2\u03b8=2sin\u03b8cos\u03b8  \u21d22 \u00d7 2sin\u03b8cos\u03b8sin2\u03b8=4  \u21d24sin\u03b8cos\u03b8sin2\u03b8=4  \u21d2sin\u03b8cos\u03b8sin2\u03b8=1  \u21d2cos\u03b8sin\u03b8=1  \u21d2sin\u03b8cos\u03b8=1  \u21d2tan\u03b8=1  \u21d2\u03b8=tan-1(1)  \u2234\u03b8=45o","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>49","subject":"Physics","year":"2023","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : THIRD LAW","question":"The following statements are observations made about a towing vehicle and a bus that is being towed  I. The force exerted on the bus by the towing vehicle is of the same magnitude as the force that the bus exerts on the road.   II. The force exerted on the bus by the towing vehicle is of the same magnitude as the force exerted on the towing vehicle by the bus.   III. The towing vehicle exerts a force on the bus greater than the force exerted by the bus on the towing vehicle.  IV. The towing vehicle exerts a force on the bus that is the same as the force the road exerts on the towing vehicle.  Which of the following statements is/are correct?","images":[],"options":{"A":"I only","B":"II only","C":"I, II and III only","D":"II, III and IV only"},"answer":"B","explanation":"According to Newton's third law of motion, the force exerted on the bus by the towing vehicle is of the same magnitude as the force exerted on the towing vehicle by the bus (Statement II). The other statements are not necessarily true.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2023>50","subject":"Physics","year":"2023","type":"Objective","topic":"SPEED AND VELOCITY : VELOCITY-TIME GRAPH","question":"The diagram above illustrates a velocity-time graph. Determine the distance between X and Y.","images":["data:image/png;base64,"],"options":{"A":"10.0 m","B":"40.0 m","C":"80.0 m","D":"160.0 m"},"answer":"D","explanation":"Distance between X and Y is the area of rectangular portion of the velocity-time graph.     XY  = 40 \u00d7 (8 - 4) = 40 \u00d7 4    \u2234  XY  = 160 m","marks":"1","difficulty":"1"}];